import { defineComponentSlotStyle, focusRingStyle } from "@yamada-ui/react"
import { menuStyle } from "../menu"
import { nativeSelectStyle } from "../native-select"

export const selectStyle = defineComponentSlotStyle({
  base: {
    ...nativeSelectStyle.base,
    content: { ...menuStyle.base?.content, maxH: "xs" },
    field: {
      ...nativeSelectStyle.base?.field,
      "--gap": "spaces.1",
      alignItems: "center",
      display: "flex",
    },
    group: menuStyle.base?.group,
    indicator: menuStyle.base?.indicator,
    label: menuStyle.base?.label,
    option: menuStyle.base?.item,
    separator: menuStyle.base?.separator,
    valueText: { userSelect: "none" },
  },

  props: {
    /**
     * If `true`, wrap the value text.
     *
     * @default false
     */
    wrap: {
      false: {
        valueText: { truncated: true },
      },
      true: {
        field: { py: "{gap}" },
        valueText: {
          display: "inline-flex",
          flexWrap: "wrap",
          gapY: "{gap}",
        },
      },
    },
  },

  variants: {
    filled: {
      ...nativeSelectStyle.variants?.filled,
      field: {
        _expanded: focusRingStyle.inside,
        _focus: focusRingStyle.inside,
        ...nativeSelectStyle.variants?.filled.field,
      },
    },
    flushed: {
      ...nativeSelectStyle.variants?.flushed,
      field: {
        _expanded: {
          ...nativeSelectStyle.variants?.flushed.field?._focusVisible,
          _invalid: {
            borderColor: "{error-border-color}",
            boxShadow: "0px 1px 0px 0px {error-border-color}",
          },
        },
        _focus: {
          ...nativeSelectStyle.variants?.flushed.field?._focusVisible,
          _invalid: {
            borderColor: "{error-border-color}",
            boxShadow: "0px 1px 0px 0px {error-border-color}",
          },
        },
        ...nativeSelectStyle.variants?.flushed.field,
      },
    },
    outline: {
      ...nativeSelectStyle.variants?.outline,
      field: {
        _expanded: focusRingStyle.inside,
        _focus: focusRingStyle.inside,
        ...nativeSelectStyle.variants?.outline.field,
      },
    },
    plain: {
      ...nativeSelectStyle.variants?.plain,
      field: {
        _expanded: focusRingStyle.inside,
        _focus: focusRingStyle.inside,
        ...nativeSelectStyle.variants?.plain.field,
      },
    },
  },

  sizes: {
    xs: {
      ...nativeSelectStyle.sizes?.xs,
      content: menuStyle.sizes?.sm.content,
      indicator: menuStyle.sizes?.sm.indicator,
      label: menuStyle.sizes?.sm.label,
      option: menuStyle.sizes?.sm.item,
    },
    sm: {
      ...nativeSelectStyle.sizes?.sm,
      content: menuStyle.sizes?.md.content,
      indicator: menuStyle.sizes?.md.indicator,
      label: menuStyle.sizes?.md.label,
      option: menuStyle.sizes?.md.item,
    },
    md: {
      ...nativeSelectStyle.sizes?.md,
      content: menuStyle.sizes?.md.content,
      indicator: menuStyle.sizes?.md.indicator,
      label: menuStyle.sizes?.md.label,
      option: menuStyle.sizes?.md.item,
    },
    lg: {
      ...nativeSelectStyle.sizes?.lg,
      content: menuStyle.sizes?.lg.content,
      indicator: menuStyle.sizes?.lg.indicator,
      label: menuStyle.sizes?.lg.label,
      option: menuStyle.sizes?.lg.item,
    },
    xl: {
      ...nativeSelectStyle.sizes?.xl,
      content: menuStyle.sizes?.lg.content,
      indicator: menuStyle.sizes?.lg.indicator,
      label: menuStyle.sizes?.lg.label,
      option: menuStyle.sizes?.lg.item,
    },
  },

  defaultProps: {
    size: "md",
    variant: "outline",
    wrap: false,
  },
})

export type SelectStyle = typeof selectStyle

import type { FC, MouseEvent as ReactMouseEvent, ReactNode } from "react"
import { act, fireEvent, screen, waitFor } from "@testing-library/react"
import { createRef, useState } from "react"
import { a11y, render, renderHook } from "#test/browser"
import { Select, useSelect } from "."

const items: Select.Item[] = [
  { label: "Option 1", value: "one" },
  { label: "Option 2", value: "two" },
  { label: "Option 3", value: "three" },
]

describe("<Select />", () => {
  test("renders component correctly", async () => {
    // Select colors come from theme tokens and can fail axe-core's
    // color-contrast rule in browser mode; this test targets component behavior.
    await a11y(
      <Select.Root placeholder="Choose a option">
        <Select.Option value="one">Option 1</Select.Option>
        <Select.Option value="two">Option 2</Select.Option>
        <Select.Option value="three">Option 3</Select.Option>
      </Select.Root>,
      {
        axeOptions: {
          rules: {
            "color-contrast": { enabled: false },
          },
        },
      },
    )
  })

  test("sets `displayName` correctly", () => {
    expect(Select.Root.displayName).toBe("SelectRoot")
    expect(Select.Group.displayName).toBe("SelectGroup")
    expect(Select.Option.displayName).toBe("SelectOption")
    expect(Select.Label.displayName).toBe("SelectLabel")
    expect(Select.Separator.displayName).toBe("SelectSeparator")
  })

  test("sets `className` correctly", async () => {
    await render(
      <Select.Root
        defaultOpen
        defaultValue="one"
        placeholder="Choose a option"
        iconProps={{ "data-testid": "icon" }}
        rootProps={{ "data-testid": "root" }}
      >
        <Select.Option value="one">Option 1</Select.Option>
        <Select.Option value="two">Option 2</Select.Option>
        <Select.Option value="three">Option 3</Select.Option>
        <Select.Separator />
        <Select.Group label="Group 1">
          <Select.Option value="one">Group Option 1</Select.Option>
          <Select.Option value="two">Group Option 2</Select.Option>
          <Select.Option value="three">Group Option 3</Select.Option>
        </Select.Group>
      </Select.Root>,
    )

    const field = screen.getByRole("combobox", { name: /Choose a option/i })
    const group = screen.getByRole("group", { name: "Group 1" })
    const option = screen.getByRole("option", { name: "Option 1" })

    expect(screen.getByTestId("root")).toHaveClass("ui-select__root")
    expect(screen.getByTestId("icon")).toHaveClass("ui-select__icon")
    expect(field).toHaveClass("ui-select__field")
    expect(field.firstChild).toHaveClass("ui-select__value-text")
    expect(option).toHaveClass("ui-select__option")
    expect(option.firstChild).toHaveClass("ui-select__indicator")
    expect(group).toHaveClass("ui-select__group")
    expect(group.firstChild).toHaveClass("ui-select__label")
    expect(screen.getByRole("separator")).toHaveClass("ui-select__separator")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <Select.Root
        defaultOpen
        defaultValue="one"
        placeholder="Choose a option"
        iconProps={{ "data-testid": "icon" }}
        rootProps={{ "data-testid": "root" }}
      >
        <Select.Option value="one">Option 1</Select.Option>
        <Select.Option value="two">Option 2</Select.Option>
        <Select.Option value="three">Option 3</Select.Option>
        <Select.Separator />
        <Select.Group label="Group 1">
          <Select.Option value="one">Group Option 1</Select.Option>
          <Select.Option value="two">Group Option 2</Select.Option>
          <Select.Option value="three">Group Option 3</Select.Option>
        </Select.Group>
      </Select.Root>,
    )

    const field = screen.getByRole("combobox", { name: /Choose a option/i })
    const group = screen.getByRole("group", { name: "Group 1" })
    const option = screen.getByRole("option", { name: "Option 1" })

    expect(screen.getByTestId("root").tagName).toBe("DIV")
    expect(screen.getByTestId("icon").tagName).toBe("DIV")
    expect(field.tagName).toBe("DIV")
    expect(field.children[0]?.tagName).toBe("SPAN")
    expect(option.tagName).toBe("DIV")
    expect(option.children[0]?.tagName).toBe("DIV")
    expect(group.tagName).toBe("DIV")
    expect(group.children[0]?.tagName).toBe("SPAN")
    expect(screen.getByRole("separator").tagName).toBe("HR")
  })

  test("selects and deselects values in multiple mode", async () => {
    const onChange = vi.fn()

    const { user } = await render(
      <Select.Root
        defaultOpen
        items={items}
        multiple
        placeholder="Choose options"
        onChange={onChange}
      />,
    )

    // Select first option
    await user.click(screen.getByRole("option", { name: "Option 1" }))
    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith(["one"])
    })

    // Select second option
    await user.click(screen.getByRole("option", { name: "Option 2" }))
    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith(["one", "two"])
    })

    // Deselect first option
    await user.click(screen.getByRole("option", { name: "Option 1" }))
    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith(["two"])
    })
  })

  test("respects max selection limit in multiple mode", async () => {
    const onChange = vi.fn()

    const { user } = await render(
      <Select.Root
        defaultOpen
        items={items}
        max={2}
        multiple
        placeholder="Choose options"
        onChange={onChange}
      />,
    )

    // Select two options (reaching max)
    await user.click(screen.getByRole("option", { name: "Option 1" }))
    await user.click(screen.getByRole("option", { name: "Option 2" }))

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith(["one", "two"])
    })

    // Attempt to select a third option - should be disabled
    await waitFor(() => {
      expect(screen.getByRole("option", { name: "Option 3" })).toHaveAttribute(
        "aria-disabled",
        "true",
      )
    })

    const callsAfterMaxReached = onChange.mock.calls.length
    fireEvent.click(screen.getByRole("option", { name: "Option 3" }))

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledTimes(callsAfterMaxReached)
    })
    expect(onChange).toHaveBeenLastCalledWith(["one", "two"])
  })

  test("displays selected values in multiple mode", async () => {
    await render(
      <Select.Root
        defaultOpen
        defaultValue={["one", "two"]}
        items={items}
        multiple
        placeholder="Choose options"
      />,
    )

    const field = screen.getByRole("combobox", { name: /Choose options/i })

    expect(field).toHaveTextContent("Option 1")
    expect(field).toHaveTextContent("Option 2")
  })

  test("displays placeholder when no value is selected in multiple mode", async () => {
    await render(
      <Select.Root items={items} multiple placeholder="Choose options" />,
    )

    const field = screen.getByRole("combobox", { name: /Choose options/i })

    expect(field).toHaveTextContent("Choose options")
  })

  test("renders clear icon and clears value when clicked", async () => {
    await render(
      <Select.Root
        clearable
        defaultValue="one"
        items={items}
        placeholder="Choose a option"
      />,
    )

    const clearButton = screen.getByRole("button", { name: /Clear value/i })

    expect(clearButton).toBeInTheDocument()

    fireEvent.click(clearButton)

    await waitFor(() => {
      const field = screen.getByRole("combobox", { name: /Choose a option/i })

      expect(field).toHaveTextContent("Choose a option")
    })
  })

  test("clears value via keyboard on clear icon", async () => {
    await render(
      <Select.Root
        clearable
        defaultValue="one"
        items={items}
        placeholder="Choose a option"
      />,
    )

    const clearButton = screen.getByRole("button", { name: /Clear value/i })

    fireEvent.keyDown(clearButton, { key: "Enter" })

    await waitFor(() => {
      const field = screen.getByRole("combobox", { name: /Choose a option/i })

      expect(field).toHaveTextContent("Choose a option")
    })
  })

  test("clears multiple values when clear icon is clicked", async () => {
    const onChange = vi.fn()

    const { user } = await render(
      <Select.Root
        clearable
        defaultValue={["one", "two"]}
        items={items}
        multiple
        placeholder="Choose options"
        onChange={onChange}
      />,
    )

    const clearButton = screen.getByRole("button", { name: /Clear value/i })

    await user.click(clearButton)

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith([])
    })
  })

  test("focuses field when input is focused", async () => {
    await render(
      <Select.Root
        name="test-select"
        items={items}
        placeholder="Choose a option"
      />,
    )

    const input = document.querySelector("input[name='test-select']")

    expect(input).toBeInTheDocument()

    fireEvent.focus(input!)

    expect(document.activeElement).toBe(
      screen.getByRole("combobox", { name: /Choose a option/i }),
    )
  })

  test("does not focus field when hidden input is focused and disabled", async () => {
    await render(
      <Select.Root
        name="disabled-select"
        disabled
        items={items}
        placeholder="Choose a option"
      />,
    )

    const input = document.querySelector(
      "input[name='disabled-select']",
    ) as HTMLInputElement

    expect(input).toBeInTheDocument()

    fireEvent.focus(input)

    const field = screen.getByRole("combobox", { name: /Choose a option/i })

    expect(document.activeElement).not.toBe(field)
  })

  test("does not focus field when disabled", async () => {
    await render(
      <Select.Root disabled items={items} placeholder="Choose a option" />,
    )

    const field = screen.getByRole("combobox", { name: /Choose a option/i })

    fireEvent.focus(field)

    expect(field).toHaveAttribute("aria-disabled", "true")
  })

  test("renders with items prop using grouped items", async () => {
    const groupedItems: Select.Item[] = [
      {
        items: [
          { label: "Option 1", value: "one" },
          { label: "Option 2", value: "two" },
        ],
        label: "Group 1",
      },
    ]

    await render(
      <Select.Root
        defaultOpen
        items={groupedItems}
        placeholder="Choose a option"
      />,
    )

    const group = screen.getByRole("group", { name: "Group 1" })

    expect(group).toBeInTheDocument()
  })

  test("does not show clear icon when clearable is false", async () => {
    await render(
      <Select.Root
        defaultValue="one"
        items={items}
        placeholder="Choose a option"
      />,
    )

    expect(
      screen.queryByRole("button", { name: /Clear value/i }),
    ).not.toBeInTheDocument()
  })

  test("does not include placeholder in options when includePlaceholder is false", async () => {
    await render(
      <Select.Root
        defaultOpen
        includePlaceholder={false}
        items={items}
        placeholder="Choose a option"
      />,
    )

    const options = screen.getAllByRole("option")
    const placeholderOption = options.find(
      (opt) => opt.textContent === "Choose a option",
    )

    expect(placeholderOption).toBeUndefined()
  })

  test("uses custom separator in multiple mode", async () => {
    await render(
      <Select.Root
        defaultValue={["one", "two"]}
        items={items}
        multiple
        placeholder="Choose options"
        separator=" | "
      />,
    )

    const field = screen.getByRole("combobox", { name: /Choose options/i })

    expect(field).toHaveTextContent("Option 1 |")
  })

  test("focuses field on clear when focusOnClear is true", async () => {
    const { user } = await render(
      <Select.Root
        clearable
        defaultValue="one"
        focusOnClear
        items={items}
        placeholder="Choose a option"
      />,
    )

    const clearButton = screen.getByRole("button", { name: /Clear value/i })

    await user.click(clearButton)

    await waitFor(() => {
      expect(document.activeElement).toBe(
        screen.getByRole("combobox", { name: /Choose a option/i }),
      )
    })
  })

  test("does not focus field on clear when focusOnClear is false", async () => {
    const { user } = await render(
      <Select.Root
        clearable
        defaultValue="one"
        focusOnClear={false}
        items={items}
        placeholder="Choose a option"
      />,
    )

    const clearButton = screen.getByRole("button", { name: /Clear value/i })

    await user.click(clearButton)

    await waitFor(() => {
      const field = screen.getByRole("combobox", { name: /Choose a option/i })

      expect(field).toHaveTextContent("Choose a option")
      expect(document.activeElement).not.toBe(field)
    })
  })

  test("works with controlled value", async () => {
    const ControlledSelect: FC = () => {
      const [value, setValue] = useState("one")

      return (
        <>
          <button data-testid="change-value" onClick={() => setValue("two")}>
            Change
          </button>
          <Select.Root
            items={items}
            placeholder="Choose a option"
            value={value}
            onChange={setValue}
          />
        </>
      )
    }

    const { user } = await render(<ControlledSelect />)

    const field = screen.getByRole("combobox", { name: /Choose a option/i })

    expect(field).toHaveTextContent("Option 1")

    await user.click(screen.getByTestId("change-value"))

    await waitFor(() => {
      expect(field).toHaveTextContent("Option 2")
    })
  })

  test("works with controlled value in multiple mode", async () => {
    const ControlledMultiSelect: FC = () => {
      const [value, setValue] = useState<string[]>(["one"])

      return (
        <>
          <button
            data-testid="change-value"
            onClick={() => setValue(["two", "three"])}
          >
            Change
          </button>
          <Select.Root
            items={items}
            multiple
            placeholder="Choose options"
            value={value}
            onChange={setValue}
          />
        </>
      )
    }

    const { user } = await render(<ControlledMultiSelect />)

    const field = screen.getByRole("combobox", { name: /Choose options/i })

    expect(field).toHaveTextContent("Option 1")

    await user.click(screen.getByTestId("change-value"))

    await waitFor(() => {
      expect(field).toHaveTextContent("Option 2")
    })
    expect(field).toHaveTextContent("Option 3")
  })

  test("clears value via Space key on clear icon", async () => {
    const onChange = vi.fn()

    await render(
      <Select.Root
        clearable
        defaultValue="one"
        items={items}
        placeholder="Choose a option"
        onChange={onChange}
      />,
    )

    const clearButton = screen.getByRole("button", { name: /Clear value/i })

    fireEvent.keyDown(clearButton, { key: " ", code: "Space" })

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith("")
    })
  })

  test("renders with custom render function returning non-element", async () => {
    await render(
      <Select.Root
        defaultValue={["one"]}
        items={items}
        multiple
        placeholder="Choose options"
        render={({ label }) => label}
      />,
    )

    const field = screen.getByRole("combobox", { name: /Choose options/i })

    expect(field).toHaveTextContent("Option 1")
  })

  test("renders with custom render function returning ReactElement", async () => {
    await render(
      <Select.Root
        defaultValue={["one", "two"]}
        items={items}
        multiple
        placeholder="Choose options"
        render={({ label, onClear }) => (
          <button data-testid="custom-tag" onClick={onClear}>
            {label}
          </button>
        )}
      />,
    )

    const tags = screen.getAllByTestId("custom-tag")

    expect(tags).toHaveLength(2)
    expect(tags[0]).toHaveTextContent("Option 1")
    expect(tags[1]).toHaveTextContent("Option 2")
  })

  test("removes selected value via custom render's onClear", async () => {
    const onChange = vi.fn()

    const { user } = await render(
      <Select.Root
        defaultValue={["one", "two"]}
        items={items}
        multiple
        placeholder="Choose options"
        render={({ label, onClear }) => (
          <button data-testid="custom-tag" onClick={onClear}>
            {label}
          </button>
        )}
        onChange={onChange}
      />,
    )

    const tags = screen.getAllByTestId("custom-tag")

    await user.click(tags[0]!)

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith(["two"])
    })
  })

  test("onClear does not call onChange when item value is empty", async () => {
    const onChange = vi.fn()

    await render(
      <Select.Root
        items={items}
        multiple
        placeholder="Choose options"
        render={({ value, onClear }) => (
          <button data-testid={`tag-${value}`} onClick={() => onClear()}>
            {value}
          </button>
        )}
        onChange={onChange}
      />,
    )

    const placeholderTag = screen.getByTestId("tag-")

    fireEvent.click(placeholderTag)
    expect(onChange).not.toHaveBeenCalled()
  })

  test("renders with readOnly", async () => {
    await render(
      <Select.Root items={items} placeholder="Choose a option" readOnly />,
    )

    const field = screen.getByRole("combobox", { name: /Choose a option/i })

    expect(field).toHaveAttribute("aria-readonly", "true")
  })

  test("renders hidden input with correct attributes", async () => {
    await render(
      <Select.Root
        id="my-select"
        name="my-select"
        defaultValue="one"
        disabled
        items={items}
        placeholder="Choose a option"
        readOnly
        required
      />,
    )

    const input = document.querySelector(
      "input[name='my-select']",
    ) as HTMLInputElement

    expect(input).toBeInTheDocument()
    expect(input).toHaveAttribute("id", "my-select")
    expect(input).toHaveAttribute("name", "my-select")
    expect(input).toBeDisabled()
    expect(input).toBeRequired()
    expect(input).toHaveAttribute("readonly")
    expect(input).toHaveValue("one")
  })

  test("renders hidden input with joined values in multiple mode", async () => {
    await render(
      <Select.Root
        name="multi-select"
        defaultValue={["one", "two"]}
        items={items}
        multiple
        placeholder="Choose options"
      />,
    )

    const input = document.querySelector(
      "input[name='multi-select']",
    ) as HTMLInputElement

    expect(input).toBeInTheDocument()
    expect(input).toHaveValue("one, two")
  })

  test("renders without placeholder", async () => {
    await render(<Select.Root defaultOpen items={items} />)

    const options = screen.getAllByRole("option")

    expect(options).toHaveLength(3)
  })

  test("renders with no items", async () => {
    await render(
      <Select.Root defaultOpen items={[]} placeholder="Choose a option" />,
    )

    const field = screen.getByRole("combobox", { name: /Choose a option/i })

    expect(field).toBeInTheDocument()
  })

  test("selects a value in single mode", async () => {
    const onChange = vi.fn()

    const { user } = await render(
      <Select.Root
        defaultOpen
        items={items}
        placeholder="Choose a option"
        onChange={onChange}
      />,
    )

    const option = screen.getByRole("option", { name: "Option 1" })

    await user.click(option)

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith("one")
    })
  })

  test("renders with grouped items and selects grouped value", async () => {
    const groupedItems: Select.Item[] = [
      {
        items: [
          { label: "Apple", value: "apple" },
          { label: "Banana", value: "banana" },
        ],
        label: "Fruits",
      },
      {
        items: [
          { label: "Carrot", value: "carrot" },
          { label: "Broccoli", value: "broccoli" },
        ],
        label: "Vegetables",
      },
    ]

    const onChange = vi.fn()

    const { user } = await render(
      <Select.Root
        defaultOpen
        items={groupedItems}
        placeholder="Choose a item"
        onChange={onChange}
      />,
    )

    const option = screen.getByRole("option", { name: "Apple" })

    await user.click(option)

    await waitFor(() => {
      expect(onChange).toHaveBeenCalledWith("apple")
    })
  })

  test("displays grouped item value correctly when selected", async () => {
    const groupedItems: Select.Item[] = [
      {
        items: [
          { label: "Apple", value: "apple" },
          { label: "Banana", value: "banana" },
        ],
        label: "Fruits",
      },
    ]

    await render(
      <Select.Root
        defaultValue="apple"
        items={groupedItems}
        placeholder="Choose a item"
      />,
    )

    const field = screen.getByRole("combobox", { name: /Choose a item/i })

    expect(field).toHaveTextContent("Apple")
  })

